    const { limit = 10, offset = 0 } = req.query;

    // Validate query parameters
    if (!Number.isInteger(Number(limit)) || limit < 1 || limit > 100) {
      return res.status(400).json({
        error: 'Invalid limit parameter. Must be integer between 1-100',
      });
