      message: 'Limit must be between 1 and 100'
    });
  }

  if (offset && (isNaN(offset) || offset < 0)) {
    return res.status(400).json({
      error: 'Invalid offset',
      message: 'Offset must be non-negative'
    });
  }

  next();
};

// ✅ 7. Health check endpoint (no sensitive data)
app.get('/health', (req, res) => {
  try {
    res.json({
      status: 'ok',
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    console.error('Health check error:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// ✅ 8. Protected users endpoint with validation
app.get('/users', validateUserQuery, (req, res) => {
  try {
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Optional filtering by ID
    if (req.query.id) {
      const userId = parseInt(req.query.id, 10);
      const user = users.find(u => u.id === userId);
      if (!user) {
        return res.status(404).json({
          error: 'Not found',
          message: `User ${userId} not found`
        });
      }
      return res.json([user]);
    }

    res.json(users);
  } catch (error) {
    console.error('Users endpoint error:', error);
    res.status(500).json({
      error: 'Internal server error',
      // Never expose error details in production
      ...(process.env.NODE_ENV === 'development' && { details: error.message })
    });
  }
});

// ✅ 9. 404 handler
app.use((req, res) => {
  res.status(404).json({
    error: 'Not found',
    message: `Cannot ${req.method} ${req.path}`
  });
});

// ✅ 10. Global error handler
app.use((err, req, res, next) => {
  const status = err.status || 500;
  const message = status === 500 
    ? 'Internal server error'
    : err.message || 'An error occurred';

  console.error(`[${status}] ${message}`, err);

  res.status(status).json({
    error: message,
    // Only expose details in development
    ...(process.env.NODE_ENV === 'development' && {
      details: err.message,
      stack: err.stack
    })
  });
});

app.listen(3000, () => {
  console.log('Server running on port 3000');
});

module.exports = app;
```

---

### **Required Dependencies to Install:**
```bash
npm install helmet express-rate-limit morgan
```

---

### **Summary of Best Practices Applied:**

| Category | Issue | Fix |
|----------|-------|-----|
| **Headers** | Missing security headers | `helmet` middleware |
| **Rate Limiting** | No DDoS protection | `express-rate-limit` |
| **Input Validation** | No parameter validation | Validation middleware |
| **Error Handling** | No try-catch | Try-catch in all routes + global error handler |
| **Logging** | No audit trail | `morgan` request logging |
| **Information Disclosure** | Exposes Express version | `app.disable('x-powered-by')` |
| **Request Size** | No size limits | Body parser limits configured |
| **Data Exposure** | Error details in production | Conditional error details based on ENV |
| **Sensitivity** | Hardcoded user data exposed | Consider authentication layer |

